        self.session = session

    def get_all(self):
        return self.session.query(User).all()

    def get_by_id(self, user_id):
        return self.session.get(User, user_id)

    def create(self, **kwargs):
        user = User(**kwargs)
        self.session.add(user)
        self.session.commit()
        self.session.refresh(user)
